info:
Default URL: https://us-central1-node-red-alerts.cloudfunctions.net/firmware_httpResolveRelease
Expected function input: POST {"data":{"target":"mcu"|"12B"|"12M"}}
Expected function result payload can be either {result:{code,type,data,msg,time}} or {code,type,data,msg,time}.

func:
const DEFAULT_RESOLVE_URL = 'https://us-central1-node-red-alerts.cloudfunctions.net/firmware_httpResolveRelease';
const rawTarget = String(msg.firmwareTarget || msg.req?.params?.target || msg.req?.query?.target || 'mcu').trim();
const normalized = rawTarget.toLowerCase();
const target = normalized === '12b' ? '12B' : normalized === '12m' ? '12M' : 'mcu';

msg._firmwareTarget = target;
msg.method = 'POST';
msg.url = String(flow.get('firmwareResolveUrl') || DEFAULT_RESOLVE_URL).trim() || DEFAULT_RESOLVE_URL;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    data: { target }
};

node.status({ fill: 'blue', shape: 'dot', text: `Resolving ${target}` });
return msg;

const target = msg._firmwareTarget || 'mcu';
const body = msg.payload || {};
const result = body.result || body.data || body;

function fail(statusCode, message, extra = {}) {
    msg.statusCode = statusCode;
    msg.headers = {
        'Content-Type': 'application/json; charset=utf-8',
        'Cache-Control': 'no-store'
    };
    msg.payload = {
        code: statusCode,
        type: 0,
        data: '',
        msg: message,
        time: Date.now(),
        target,
        ...extra
    };
    node.status({ fill: 'red', shape: 'ring', text: `${target}: ${message}` });
    return msg;
}

if (body.error) {
    return fail(Number(msg.statusCode || 500), body.error.message || body.error.status || 'Firmware resolver error', {
        error: body.error
    });
}

if (!result || Number(result.code) !== 200 || !result.data) {
    return fail(502, 'No active firmware metadata returned', {
        resolverPayload: result || null
    });
}

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json; charset=utf-8',
    'Cache-Control': 'no-store'
};
msg.payload = {
    code: 200,
    type: Number(result.type || 0),
    data: String(result.data),
    msg: result.msg || 'ok',
    time: Number(result.time || Date.now())
};

node.status({ fill: 'green', shape: 'dot', text: `${target}: ${msg.payload.data.split(',')[0]}` });
return msg;

const message = msg.error?.message || 'Firmware endpoint failed';
msg.statusCode = 500;
msg.headers = {
    'Content-Type': 'application/json; charset=utf-8',
    'Cache-Control': 'no-store'
};
msg.payload = {
    code: 500,
    type: 0,
    data: '',
    msg: message,
    time: Date.now(),
    target: msg._firmwareTarget || msg.firmwareTarget || ''
};
node.status({ fill: 'red', shape: 'ring', text: message });
return msg;
